// Auto-generated — efesios (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const EFESIOS_NVI: Record<number, string[]> = {
  1: ["Pablo, apóstol de Cristo Jesús por la voluntad de Dios, a los santos y fieles[1] en Cristo Jesús que están en Éfeso:[2]","Que Dios nuestro Padre y el Señor Jesucristo les concedan gracia y paz.","Alabado sea Dios, Padre de nuestro Señor Jesucristo, que nos ha bendecido en las regiones celestiales con toda bendición espiritual en Cristo.","Dios nos escogió en él antes de la creación del mundo, para que seamos santos y sin mancha delante de él. En amor","nos predestinó para ser adoptados como hijos suyos por medio de Jesucristo, según el buen propósito de su voluntad,","para alabanza de su gloriosa gracia, que nos concedió en su Amado.","En él tenemos la redención mediante su sangre, el perdón de nuestros pecados, conforme a las riquezas de la gracia","que Dios nos dio en abundancia con toda sabiduría y entendimiento.","Él nos hizo conocer el misterio de su voluntad conforme al buen propósito que de antemano estableció en Cristo,","para llevarlo a cabo cuando se cumpliera el tiempo, esto es, reunir en él todas las cosas, tanto las del cielo como las de la tierra.","En Cristo también fuimos hechos herederos,[3] pues fuimos predestinados según el plan de aquel que hace todas las cosas conforme al designio de su voluntad,","a fin de que nosotros, que ya hemos puesto nuestra esperanza en Cristo, seamos para alabanza de su gloria.","En él también ustedes, cuando oyeron el mensaje de la verdad, el evangelio que les trajo la salvación, y lo creyeron, fueron marcados con el sello que es el Espíritu Santo prometido.","Este garantiza nuestra herencia hasta que llegue la redención final del pueblo adquirido por Dios,[4] para alabanza de su gloria.","Por eso yo, por mi parte, desde que me enteré de la fe que tienen en el Señor Jesús y del amor que demuestran por todos los santos,","no he dejado de dar gracias por ustedes al recordarlos en mis oraciones.","Pido que el Dios de nuestro Señor Jesucristo, el Padre glorioso, les dé el Espíritu de sabiduría y de revelación, para que lo conozcan mejor.","Pido también que les sean iluminados los ojos del corazón para que sepan a qué esperanza él los ha llamado, cuál es la riqueza de su gloriosa herencia entre los santos,","y cuán incomparable es la grandeza de su poder a favor de los que creemos. Ese poder es la fuerza grandiosa y eficaz","que Dios ejerció en Cristo cuando lo resucitó de entre los muertos y lo sentó a su derecha en las regiones celestiales,","muy por encima de todo gobierno y autoridad, poder y dominio, y de cualquier otro nombre que se invoque, no solo en este mundo, sino también en el venidero.","Dios sometió todas las cosas al dominio de Cristo,[5] y lo dio como cabeza de todo a la iglesia.","Esta, que es su cuerpo, es la plenitud de aquel que lo llena todo por completo."],
  2: ["En otro tiempo ustedes estaban muertos en sus transgresiones y pecados,","en los cuales andaban conforme a los poderes de este mundo. Se conducían según el que gobierna las tinieblas, según el espíritu que ahora ejerce su poder en los que viven en la desobediencia.","En ese tiempo también todos nosotros vivíamos como ellos, impulsados por nuestros deseos pecaminosos, siguiendo nuestra propia voluntad y nuestros propósitos.[6] Como los demás, éramos por naturaleza objeto de la ira de Dios.","Pero Dios, que es rico en misericordia, por su gran amor por nosotros,","nos dio vida con Cristo, aun cuando estábamos muertos en pecados. ¡Por gracia ustedes han sido salvados!","Y en unión con Cristo Jesús, Dios nos resucitó y nos hizo sentar con él en las regiones celestiales,","para mostrar en los tiempos venideros la incomparable riqueza de su gracia, que por su bondad derramó sobre nosotros en Cristo Jesús.","Porque por gracia ustedes han sido salvados mediante la fe; esto no procede de ustedes, sino que es el regalo de Dios,","no por obras, para que nadie se jacte.","Porque somos hechura de Dios, creados en Cristo Jesús para buenas obras, las cuales Dios dispuso de antemano a fin de que las pongamos en práctica.","Por lo tanto, recuerden ustedes los gentiles de nacimiento —los que son llamados «incircuncisos» por aquellos que se llaman «de la circuncisión», la cual se hace en el cuerpo por mano humana—,","recuerden que en ese entonces ustedes estaban separados de Cristo, excluidos de la ciudadanía de Israel y ajenos a los pactos de la promesa, sin esperanza y sin Dios en el mundo.","Pero ahora en Cristo Jesús, a ustedes que antes estaban lejos, Dios los ha acercado mediante la sangre de Cristo.","Porque Cristo es nuestra paz: de los dos pueblos ha hecho uno solo, derribando mediante su sacrificio[7] el muro de enemistad que nos separaba,","pues anuló la ley con sus mandamientos y requisitos. Esto lo hizo para crear en sí mismo de los dos pueblos una nueva humanidad al hacer la paz,","para reconciliar con Dios a ambos en un solo cuerpo mediante la cruz, por la que dio muerte a la enemistad.","Él vino y proclamó paz a ustedes que estaban lejos y paz a los que estaban cerca.","Pues por medio de él tenemos acceso al Padre por un mismo Espíritu.","Por lo tanto, ustedes ya no son extraños ni extranjeros, sino conciudadanos de los santos y miembros de la familia de Dios,","edificados sobre el fundamento de los apóstoles y los profetas, siendo Cristo Jesús mismo la piedra angular.","En él todo el edificio, bien armado, se va levantando para llegar a ser un templo santo en el Señor.","En él también ustedes son edificados juntamente para ser morada de Dios por su Espíritu."],
  3: ["Por esta razón yo, Pablo, prisionero de Cristo Jesús por el bien de ustedes los gentiles, me arrodillo en oración.[8]","Sin duda se han enterado del plan de la gracia de Dios que él me encomendó para ustedes,","es decir, el misterio que me dio a conocer por revelación, como ya les escribí brevemente.","Al leer esto, podrán darse cuenta de que comprendo el misterio de Cristo.","Ese misterio, que en otras generaciones no se les dio a conocer a los seres humanos, ahora se les ha revelado por el Espíritu a los santos apóstoles y profetas de Dios;","es decir, que los gentiles son, junto con Israel, beneficiarios de la misma herencia, miembros de un mismo cuerpo y participantes igualmente de la promesa en Cristo Jesús mediante el evangelio.","De este evangelio llegué a ser servidor. Este fue el regalo que Dios me dio por su gracia, conforme a su poder eficaz.","Aunque soy el más insignificante de todos los santos, recibí esta gracia de predicar a las naciones las incalculables riquezas de Cristo,","y de hacer entender a todos la realización del plan de Dios, el misterio que desde los tiempos eternos se mantuvo oculto en Dios, creador de todas las cosas.","El fin de todo esto es que la sabiduría de Dios, en toda su diversidad, se dé a conocer ahora, por medio de la iglesia, a los poderes y autoridades en las regiones celestiales,","conforme a su eterno propósito realizado en Cristo Jesús nuestro Señor.","En él, mediante la fe, disfrutamos de libertad y confianza para acercarnos a Dios.","Así que les pido que no se desanimen a causa de lo que sufro por ustedes, ya que estos sufrimientos míos son para ustedes un honor.","Por esta razón me arrodillo delante del Padre,","de quien recibe nombre toda familia[9] en el cielo y en la tierra.","Le pido que, por medio del Espíritu y con el poder que procede de sus gloriosas riquezas, los fortalezca a ustedes en lo íntimo de su ser,","para que por fe Cristo habite en sus corazones. Y pido que, arraigados y cimentados en amor,","puedan comprender, junto con todos los santos, cuán ancho y largo, alto y profundo es el amor de Cristo;","en fin, que conozcan ese amor que sobrepasa nuestro conocimiento, para que sean llenos de la plenitud de Dios.","Al que puede hacer muchísimo más que todo lo que podamos imaginarnos o pedir, por el poder que obra eficazmente en nosotros,","¡a él sea la gloria en la iglesia y en Cristo Jesús por todas las generaciones, por los siglos de los siglos! Amén."],
  4: ["Por eso yo, que estoy preso por la causa del Señor, les ruego que vivan de una manera digna del llamamiento que han recibido,","siempre humildes y amables, pacientes, tolerantes unos con otros en amor.","Esfuércense por mantener la unidad del Espíritu mediante el vínculo de la paz.","Hay un solo cuerpo y un solo Espíritu, así como también fueron llamados a una sola esperanza;","un solo Señor, una sola fe, un solo bautismo;","un solo Dios y Padre de todos, que está sobre todos y por medio de todos y en todos.","Pero a cada uno de nosotros se nos ha dado gracia en la medida en que Cristo ha repartido los dones.","Por esto dice: «Cuando ascendió a lo alto, se llevó consigo a los cautivos y dio dones a los hombres».[10]","(¿Qué quiere decir eso de que «ascendió», sino que también descendió a las partes bajas, o sea, a la tierra?[11]","El que descendió es el mismo que ascendió por encima de todos los cielos, para llenarlo todo).","Él mismo constituyó a unos, apóstoles; a otros, profetas; a otros, evangelistas; y a otros, pastores y maestros,","a fin de capacitar al pueblo de Dios para la obra de servicio, para edificar el cuerpo de Cristo.","De este modo, todos llegaremos a la unidad de la fe y del conocimiento del Hijo de Dios, a una humanidad perfecta que se conforme a la plena estatura de Cristo.","Así ya no seremos niños, zarandeados por las olas y llevados de aquí para allá por todo viento de enseñanza y por la astucia y los artificios de quienes emplean artimañas engañosas.","Más bien, al vivir la verdad con amor, creceremos hasta ser en todo como aquel que es la cabeza, es decir, Cristo.","Por su acción todo el cuerpo crece y se edifica en amor, sostenido y ajustado por todos los ligamentos, según la actividad propia de cada miembro.","Así que les digo esto y les insisto en el Señor: no vivan más con pensamientos frívolos como los paganos.","A causa de la ignorancia que los domina y por la dureza de su corazón, estos tienen oscurecido el entendimiento y están alejados de la vida que proviene de Dios.","Han perdido toda vergüenza, se han entregado a la inmoralidad, y no se sacian de cometer toda clase de actos indecentes.","No fue esta la enseñanza que ustedes recibieron acerca de Cristo,","si de veras se les habló y enseñó de Jesús según la verdad que está en él.","Con respecto a la vida que antes llevaban, se les enseñó que debían quitarse el ropaje de la vieja naturaleza, la cual está corrompida por los deseos engañosos;","ser renovados en la actitud de su mente;","y ponerse el ropaje de la nueva naturaleza, creada a imagen de Dios, en verdadera justicia y santidad.","Por lo tanto, dejando la mentira, hable cada uno a su prójimo con la verdad, porque todos somos miembros de un mismo cuerpo.","«Si se enojan, no pequen».[12] No permitan que el enojo les dure hasta la puesta del sol,","ni den cabida al diablo.","El que robaba, que no robe más, sino que trabaje honradamente con las manos para tener qué compartir con los necesitados.","Eviten toda conversación obscena. Por el contrario, que sus palabras contribuyan a la necesaria edificación y sean de bendición para quienes escuchan.","No agravien al Espíritu Santo de Dios, con el cual fueron sellados para el día de la redención.","Abandonen toda amargura, ira y enojo, gritos y calumnias, y toda forma de malicia.","Más bien, sean bondadosos y compasivos unos con otros, y perdónense mutuamente, así como Dios los perdonó a ustedes en Cristo."],
  5: ["Por tanto, imiten a Dios, como hijos muy amados,","y lleven una vida de amor, así como Cristo nos amó y se entregó por nosotros como ofrenda y sacrificio fragante para Dios.","Entre ustedes ni siquiera debe mencionarse la inmoralidad sexual, ni ninguna clase de impureza o de avaricia, porque eso no es propio del pueblo santo de Dios.","Tampoco debe haber palabras indecentes, conversaciones necias ni chistes groseros, todo lo cual está fuera de lugar; haya más bien acción de gracias.","Porque pueden estar seguros de que nadie que sea avaro (es decir, idólatra), inmoral o impuro tendrá herencia en el reino de Cristo y de Dios.[13]","Que nadie los engañe con argumentaciones vanas, porque por esto viene el castigo de Dios sobre los que viven en la desobediencia.","Así que no se hagan cómplices de ellos.","Porque ustedes antes eran oscuridad, pero ahora son luz en el Señor. Vivan como hijos de luz","(el fruto de la luz consiste en toda bondad, justicia y verdad)","y comprueben lo que agrada al Señor.","No tengan nada que ver con las obras infructuosas de la oscuridad, sino más bien denúncienlas,","porque da vergüenza aun mencionar lo que los desobedientes hacen en secreto.","Pero todo lo que la luz pone al descubierto se hace visible,","porque la luz es lo que hace que todo sea visible. Por eso se dice: «Despiértate, tú que duermes, levántate de entre los muertos, y te alumbrará Cristo».","Así que tengan cuidado de su manera de vivir. No vivan como necios, sino como sabios,","aprovechando al máximo cada momento oportuno, porque los días son malos.","Por tanto, no sean insensatos, sino entiendan cuál es la voluntad del Señor.","No se emborrachen con vino, que lleva al desenfreno. Al contrario, sean llenos del Espíritu.","Anímense unos a otros con salmos, himnos y canciones espirituales. Canten y alaben al Señor con el corazón,","dando siempre gracias a Dios el Padre por todo, en el nombre de nuestro Señor Jesucristo.","Sométanse unos a otros, por reverencia a Cristo.","Esposas, sométanse a sus propios esposos como al Señor.","Porque el esposo es cabeza de su esposa, así como Cristo es cabeza y Salvador de la iglesia, la cual es su cuerpo.","Así como la iglesia se somete a Cristo, también las esposas deben someterse a sus esposos en todo.","Esposos, amen a sus esposas, así como Cristo amó a la iglesia y se entregó por ella","para hacerla santa. Él la purificó, lavándola con agua mediante la palabra,","para presentársela a sí mismo como una iglesia radiante, sin mancha ni arruga ni ninguna otra imperfección, sino santa e intachable.","Así mismo el esposo debe amar a su esposa como a su propio cuerpo. El que ama a su esposa se ama a sí mismo,","pues nadie ha odiado jamás a su propio cuerpo; al contrario, lo alimenta y lo cuida, así como Cristo hace con la iglesia,","porque somos miembros de su cuerpo.","«Por eso dejará el hombre a su padre y a su madre, y se unirá a su esposa, y los dos llegarán a ser un solo cuerpo».[14]","Esto es un misterio profundo; yo me refiero a Cristo y a la iglesia.","En todo caso, cada uno de ustedes ame también a su esposa como a sí mismo, y que la esposa respete a su esposo."],
  6: ["Hijos, obedezcan en el Señor a sus padres, porque esto es justo.","«Honra a tu padre y a tu madre —que es el primer mandamiento con promesa—","para que te vaya bien y disfrutes de una larga vida en la tierra».[15]","Y ustedes, padres, no hagan enojar a sus hijos, sino críenlos según la disciplina e instrucción del Señor.","Esclavos, obedezcan a sus amos terrenales con respeto y temor, y con integridad de corazón, como a Cristo.","No lo hagan solo cuando los estén mirando, como los que quieren ganarse el favor humano, sino como esclavos de Cristo, haciendo de todo corazón la voluntad de Dios.","Sirvan de buena gana, como quien sirve al Señor y no a los hombres,","sabiendo que el Señor recompensará a cada uno por el bien que haya hecho, sea esclavo o sea libre.","Y ustedes, amos, correspondan a esta actitud de sus esclavos, dejando de amenazarlos. Recuerden que tanto ellos como ustedes tienen un mismo Amo[16] en el cielo, y que con él no hay favoritismos.","Por último, fortalézcanse con el gran poder del Señor.","Pónganse toda la armadura de Dios para que puedan hacer frente a las artimañas del diablo.","Porque nuestra lucha no es contra seres humanos, sino contra poderes, contra autoridades, contra potestades que dominan este mundo de tinieblas, contra fuerzas espirituales malignas en las regiones celestiales.","Por lo tanto, pónganse toda la armadura de Dios, para que cuando llegue el día malo puedan resistir hasta el fin con firmeza.","Manténganse firmes, ceñidos con el cinturón de la verdad, protegidos por la coraza de justicia,","y calzados con la disposición de proclamar el evangelio de la paz.","Además de todo esto, tomen el escudo de la fe, con el cual pueden apagar todas las flechas encendidas del maligno.","Tomen el casco de la salvación y la espada del Espíritu, que es la palabra de Dios.","Oren en el Espíritu en todo momento, con peticiones y ruegos. Manténganse alerta y perseveren en oración por todos los santos.","Oren también por mí para que, cuando hable, Dios me dé las palabras para dar a conocer con valor el misterio del evangelio,","por el cual soy embajador en cadenas. Oren para que lo proclame valerosamente, como debo hacerlo.","Nuestro querido hermano Tíquico, fiel servidor en el Señor, les contará todo, para que también ustedes sepan cómo me va y qué estoy haciendo.","Lo envío a ustedes precisamente para que sepan cómo estamos y para que cobren ánimo.","Que Dios el Padre y el Señor Jesucristo les concedan paz, amor y fe a los hermanos.","La gracia sea con todos los que aman a nuestro Señor Jesucristo con amor imperecedero."],
};
